from flask import Blueprint, request, jsonify
from yourapp.models import Post, User
from yourapp.extensions import db
from yourapp.utils.auth import current_user

posts_blueprint = Blueprint('posts', __name__)

@posts_blueprint.route('/posts/<int:post_id>', methods=['DELETE'])
def delete_post(post_id):
    post = Post.query.get(post_id)
    
    if not post:
        return jsonify({'error': 'Post not found'}), 404
    
    if current_user.id != post.user_id and not current_user.is_admin:
        return jsonify({'error': 'Forbidden'}), 403
    
    db.session.delete(post)
    db.session.commit()
    
    return jsonify({'message': 'Post deleted successfully'}), 200